const InsightSection = defineComponent({ props: { title: String, dot: String }, setup: (props, { slots }) => () => h('section', [h('div', { class: 'mb-1 flex items-center gap-1 font-semibold text-slate-700' }, [props.dot ? h('span', { class: `h-1.5 w-1.5 rounded-full ${props.dot}` }) : null, props.title]), slots.default?.()]) })
