const StatCard = defineComponent({ props: { label: String, value: Number, icon: String, tone: String }, setup: (props) => () => h('div', { class: 'rounded-lg border border-slate-200 bg-white p-4 shadow-sm' }, [h('div', { class: 'flex items-center justify-between' }, [h('div', [h('div', { class: 'text-sm text-slate-500' }, props.label), h('div', { class: 'mt-2 text-2xl font-bold text-slate-900' }, String(props.value))]), h('div', { class: 'flex h-10 w-10 items-center justify-center rounded-lg border border-slate-200 bg-slate-50 text-lg' }, props.icon)])]) })

