const statusOptions = [{ label: '待处理', value: 'pending' }, { label: '进行中', value: 'in_progress' }, { label: '已完成', value: 'completed' }, { label: '已取消', value: 'cancelled' }]; const taskTypeOptions = [{ label: '回复候选人', value: 'reply_candidate' }, { label: '确认面试信息', value: 'confirm_interview_information' }, { label: '跟进补充材料', value: 'follow_up_materials' }, { label: '风险复核', value: 'review_risk' }, { label: '跟进候选人', value: 'follow_up' }]
const filteredSessions = computed(() => { const keyword = sessionSearch.value.trim().toLowerCase(); return !keyword ? conversations.value : conversations.value.filter((item) => `${item.candidate_name} ${item.position_title}`.toLowerCase().includes(keyword)) }); const unreadCount = computed(() => conversations.value.filter((item) => item.unread_count > 0).length); const pendingTasks = computed(() => tasks.value.filter((task) => ['pending', 'in_progress'].includes(task.status))); const highPriorityTasks = computed(() => tasks.value.filter((task) => task.priority === 'high' && !['completed', 'cancelled'].includes(task.status))); const completedTasks = computed(() => tasks.value.filter((task) => task.status === 'completed')); const overdueTasks = computed(() => tasks.value.filter(isOverdue)); const relatedTasks = computed(() => tasks.value.filter((task) => task.candidate_id === selectedId.value && !['completed', 'cancelled'].includes(task.status))); const positionOptions = computed(() => [...new Set(tasks.value.map((task) => task.position_title).filter(Boolean))] as string[]); const isAnalyzing = computed(() => detail.value?.analysis_status === 'pending' || detail.value?.analysis_status === 'processing'); const filteredTasks = computed(() => tasks.value.filter((task) => { const keyword = todoKeyword.value.trim().toLowerCase(); return (!keyword || `${task.candidate_name} ${task.position_title} ${task.title}`.toLowerCase().includes(keyword)) && (!todoTaskType.value || task.task_type === todoTaskType.value) && (!todoStatus.value || task.status === todoStatus.value) && (!todoPriority.value || task.priority === todoPriority.value) && (!todoPosition.value || task.position_title === todoPosition.value) && (!overdueOnly.value || isOverdue(task)) }))
const navClass = (target: 'chat' | 'todo') => ['mb-2 flex w-full items-center gap-2 rounded-r-lg px-4 py-3 text-left text-sm transition', view.value === target ? 'border-l-4 border-blue-600 bg-blue-50 font-semibold text-blue-700' : 'text-slate-600 hover:bg-slate-100'].join(' '); const formatTime = (value?: string | null) => value ? new Date(value).toLocaleString('zh-CN', { month: '2-digit', day: '2-digit', hour: '2-digit', minute: '2-digit' }) : '-'; const taskTypeLabel = (value: string) => taskTypeOptions.find((item) => item.value === value)?.label || '跟进候选人'; const priorityLabel = (value: string) => ({ high: '高', medium: '中', low: '低' })[value] || value; const priorityTag = (value: string) => value === 'high' ? 'danger' : value === 'medium' ? 'warning' : 'info'; const taskStatusLabel = (value: string) => statusOptions.find((item) => item.value === value)?.label || value; const taskStatusTag = (value: string) => value === 'completed' ? 'success' : value === 'cancelled' ? 'info' : value === 'in_progress' ? 'warning' : 'primary'; const candidateStatusTag = (value: string) => value.includes('通过') || value.includes('入职') ? 'success' : value.includes('拒绝') || value.includes('未通过') ? 'danger' : 'info'; const isOverdue = (task: FollowupTask) => Boolean(task.due_at && new Date(task.due_at).getTime() < Date.now() && !['completed', 'cancelled'].includes(task.status))
const scrollDown = async () => { await nextTick(); if (messageBox.value) messageBox.value.scrollTop = messageBox.value.scrollHeight }; const loadConversations = async () => { conversations.value = (await getCommunicationConversations()).items }; const loadTasks = async (notify = false) => { const fresh = (await getFollowupTasks()).items; if (notify) fresh.filter((task) => !seenTaskIds.has(task.id)).forEach((task) => ElNotification({ title: 'AI 待办提醒', message: task.title, type: 'info' })); fresh.forEach((task) => seenTaskIds.add(task.id)); tasks.value = fresh }
const selectConversation = async (candidateId: string) => { selectedId.value = candidateId; detail.value = await getCommunicationDetail(candidateId); await markCommunicationRead(candidateId); const current = conversations.value.find((item) => item.candidate_id === candidateId); if (current) current.unread_count = 0; await scrollDown() }; const sendReply = async () => { if (!replyDraft.value.trim() || !selectedId.value) return; replying.value = true; try { const result = await sendHRCommunicationMessage(selectedId.value, replyDraft.value.trim()); detail.value?.messages.push(result.message); replyDraft.value = ''; await scrollDown() } catch { ElMessage.error('发送失败，请稍后重试') } finally { replying.value = false } }; const locateEvidence = async (evidence: { message_id: string }[]) => { const id = evidence[0]?.message_id; if (!id) return ElMessage.info('该项暂无可定位的消息证据'); highlightedMessageId.value = id; await nextTick(); document.getElementById(`message-${id}`)?.scrollIntoView({ behavior: 'smooth', block: 'center' }); window.setTimeout(() => { highlightedMessageId.value = '' }, 2500) }
const openTask = async (task: FollowupTask) => { taskDetail.value = await getFollowupTaskDetail(task.id); taskDrawer.value = true }; const openTaskConversation = async (task: FollowupTask) => { view.value = 'chat'; await selectConversation(task.candidate_id); taskDrawer.value = false; await locateEvidence(task.evidence) }; const changeTaskStatus = async (taskId: string, status: FollowupTask['status']) => { try { await updateFollowupTask(taskId, status); await loadTasks(); if (taskDetail.value?.task.id === taskId) taskDetail.value.task.status = status; ElMessage.success('待办状态已更新') } catch { ElMessage.error('更新失败') } }; const addNote = async () => { if (!noteDraft.value.trim() || !taskDetail.value) return; addingNote.value = true; try { const result = await addFollowupTaskNote(taskDetail.value.task.id, noteDraft.value.trim()); taskDetail.value.notes.push(result.note); noteDraft.value = ''; ElMessage.success('处理备注已添加') } catch { ElMessage.error('备注添加失败') } finally { addingNote.value = false } }; const resetFilters = () => { todoKeyword.value = ''; todoTaskType.value = ''; todoStatus.value = ''; todoPriority.value = ''; todoPosition.value = ''; overdueOnly.value = false }
onMounted(async () => { try { await Promise.all([loadConversations(), loadTasks()]); if (conversations.value[0]) await selectConversation(conversations.value[0].candidate_id); timer = window.setInterval(() => { if (document.visibilityState === 'visible') { void loadTasks(true); if (selectedId.value) void selectConversation(selectedId.value) } }, 15000) } catch { ElMessage.error('候选人沟通数据加载失败') } }); onBeforeUnmount(() => { if (timer) window.clearInterval(timer) })
</script>

