.message-highlight { animation: highlight-pulse 1.5s ease-in-out infinite alternate; border: 2px solid #3b82f6 !important; background: #eff6ff !important; }
@keyframes highlight-pulse { from { box-shadow: 0 0 0 0 rgba(59, 130, 246, .35); } to { box-shadow: 0 0 0 8px rgba(59, 130, 246, .12); } }
</style>
